import{_ as a,o as i,c as e,a2 as n}from"./chunks/framework.BflysNKA.js";const l="/images/hapi-remote-flow.svg",u=JSON.parse('{"title":"Hapi 远程控制","description":"","frontmatter":{},"headers":[],"relativePath":"apps/hapi.md","filePath":"apps/hapi.md","lastUpdated":1778577020000}'),p={name:"apps/hapi.md"};function t(h,s,r,d,o,c){return i(),e("div",null,[...s[0]||(s[0]=[n('<h1 id="hapi-远程控制" tabindex="-1">Hapi 远程控制 <a class="header-anchor" href="#hapi-远程控制" aria-label="Permalink to &quot;Hapi 远程控制&quot;">​</a></h1><p>HAPI 适合“终端工作流已经跑通，但你还想从手机、浏览器或另一台设备继续控制同一个会话”的场景。</p><p>它本身不是模型 Provider，也不是单独的聊天客户端。HAPI 的作用是把你已经装好的 Claude Code、Codex、Gemini CLI、OpenCode 这类工具包起来，再把会话同步到远端网页或手机端。</p><p><img src="'+l+`" alt="HAPI 远程控制关系图"></p><h2 id="先理解-hapi-在链路里的位置" tabindex="-1">先理解 HAPI 在链路里的位置 <a class="header-anchor" href="#先理解-hapi-在链路里的位置" aria-label="Permalink to &quot;先理解 HAPI 在链路里的位置&quot;">​</a></h2><p>接入 HAPI 时，最容易搞混的一点是：<strong>HAPI 不替你配置模型网关，模型仍然由底层 CLI 去调用。</strong></p><p>也就是说：</p><ul><li>你想用 Claude Code 走 小蓝中转站，先看 <a href="/deploy/claude-code">Claude Code 部署</a></li><li>你想用 Codex 走 小蓝中转站，先看 <a href="/deploy/codex">Codex 部署</a></li><li>你想用 Gemini CLI 走 小蓝中转站，先看 <a href="/deploy/gemini-cli">Gemini CLI 部署</a></li><li>你想用 OpenCode 走 小蓝中转站，先看 <a href="/apps/opencode">OpenCode</a></li></ul><p>先把其中一个 CLI 本地跑通，再上 HAPI，排障会清楚很多。否则你遇到“远程会话打不开”时，很难判断到底是 HAPI 问题，还是底层模型配置根本没通。</p><h2 id="下载与安装" tabindex="-1">下载与安装 <a class="header-anchor" href="#下载与安装" aria-label="Permalink to &quot;下载与安装&quot;">​</a></h2><p>官方入口：</p><ul><li>官网：<a href="https://hapi.run/" target="_blank" rel="noreferrer">https://hapi.run/</a></li><li>Quick Start：<a href="https://hapi.run/docs/guide/quick-start.html" target="_blank" rel="noreferrer">https://hapi.run/docs/guide/quick-start.html</a></li><li>Installation：<a href="https://hapi.run/docs/guide/installation.html" target="_blank" rel="noreferrer">https://hapi.run/docs/guide/installation.html</a></li><li>How it Works：<a href="https://hapi.run/docs/guide/how-it-works.html" target="_blank" rel="noreferrer">https://hapi.run/docs/guide/how-it-works.html</a></li><li>GitHub Releases：<a href="https://github.com/tiann/hapi/releases" target="_blank" rel="noreferrer">https://github.com/tiann/hapi/releases</a></li></ul><p>HAPI 官方当前给出的安装方式包括：</p><ul><li><code>npm install -g @twsxtd/hapi</code></li><li><code>brew install tiann/tap/hapi</code></li><li><code>npx @twsxtd/hapi</code></li><li>GitHub Releases 里的预编译二进制</li></ul><h2 id="为什么-hapi-安装时不建议强行用-npm-镜像" tabindex="-1">为什么 HAPI 安装时不建议强行用 npm 镜像 <a class="header-anchor" href="#为什么-hapi-安装时不建议强行用-npm-镜像" aria-label="Permalink to &quot;为什么 HAPI 安装时不建议强行用 npm 镜像&quot;">​</a></h2><p>HAPI 官方安装页特别提醒：全局安装时优先使用官方 npm registry，因为镜像站有时不会及时同步它依赖的平台包。</p><p>这意味着它和前面多数 CLI 不太一样：</p><ul><li>对 Claude Code、Codex、普通 npm CLI，镜像通常更稳</li><li>对 HAPI，自身安装阶段优先按官方建议走 <code>registry.npmjs.org</code> 更保险</li></ul><p>平时已经把 npm registry 切到镜像时，更省事的做法不是全局来回切换，而是只在这一条安装命令里指定官方源：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> @twsxtd/hapi</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> --registry=https://registry.npmjs.org</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">hapi</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> --version</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这样做的好处是，HAPI 能按官方建议从 <code>registry.npmjs.org</code> 拉依赖，但你平时给其他工具准备的镜像配置不会被改掉。</p><p>更习惯先切全局源再装时，也可以这样做：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> config</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> set</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> registry</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> https://registry.npmjs.org</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> @twsxtd/hapi</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">hapi</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> --version</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> config</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> set</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> registry</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> https://registry.npmmirror.com</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>本来就用 Homebrew 时，也可以直接安装：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> tiann/tap/hapi</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">hapi</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> --version</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="接入前先准备" tabindex="-1">接入前先准备 <a class="header-anchor" href="#接入前先准备" aria-label="Permalink to &quot;接入前先准备&quot;">​</a></h2><p>按 HAPI 官方安装页，先确认你已经装好了至少一种底层 AI CLI：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> --version</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">codex</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> --version</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">gemini</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> --version</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">opencode</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> --version</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>不需要四个都装。你准备远程控制哪个，就先把哪个本地跑通。</p><h2 id="最常见的一条接入路径" tabindex="-1">最常见的一条接入路径 <a class="header-anchor" href="#最常见的一条接入路径" aria-label="Permalink to &quot;最常见的一条接入路径&quot;">​</a></h2><p>希望从手机或浏览器继续控制 Claude Code 时，常见顺序是：</p><ol><li>先按 <a href="/deploy/claude-code">Claude Code 部署</a> 把本地网关配置好</li><li>安装 HAPI</li><li>启动 HAPI Hub</li><li>用 <code>hapi</code> 启动会话</li><li>用浏览器或手机打开 HAPI 给出的地址继续控制</li></ol><p>控制的是 Codex、Gemini CLI 或 OpenCode 时，就把第 1 步换成对应页面，然后在第 4 步使用相应命令。</p><h2 id="启动-hapi-hub" tabindex="-1">启动 HAPI Hub <a class="header-anchor" href="#启动-hapi-hub" aria-label="Permalink to &quot;启动 HAPI Hub&quot;">​</a></h2><p>只想本机浏览器访问时：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">hapi</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> hub</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 或</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">hapi</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> hub</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> --no-relay</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>这一层默认监听的是：</p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span>http://localhost:3006</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这也是最适合第一次验证的一层。<br> 因为只要本机能打开 <code>http://localhost:3006</code>，就说明 Hub 本身已经起来了，后面再去看 Relay、手机访问或公网入口时，排障范围会小很多。</p><p>只是想让同一 Wi-Fi 下的手机或另一台电脑接入，而不是立刻走公网 Relay 时，可以先把监听地址放开：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;"> HAPI_LISTEN_HOST</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">0.0.0.0</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">hapi</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> hub</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> --no-relay</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>然后在同局域网设备里访问：</p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span>http://你的电脑局域网 IP:3006</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这样做的意义，是先把“本地局域网访问”和“公网 Relay 访问”拆开。<br> 同局域网能打开，说明 Hub、端口和浏览器这层基本没问题；后面如果外网不稳定，你就知道该继续看 Relay 或公网入口，而不是回头怀疑模型配置。</p><p>想让手机或外部网络也能接进来时：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">hapi</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> hub</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> --relay</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 或</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">hapi</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> server</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> --relay</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>按 HAPI 官方 Quick Start，首次运行时会：</p><ul><li>在终端里打印访问地址</li><li>显示二维码</li><li>生成访问令牌</li><li>把令牌保存到 <code>~/.hapi/settings.json</code></li></ul><p><code>hapi server</code> 目前仍然是兼容别名，所以你在一些旧教程里看到 <code>hapi server</code> 不代表那篇教程一定错了。<br> 只是现在官方文档已经更多使用 <code>hapi hub</code> 这个名字。</p><p>这一层解决的是“远程访问会话”的问题，不是“模型怎么调用”的问题。只要底层 CLI 已经接好了 小蓝中转站，HAPI 就会把那个已有会话同步出来。</p><h2 id="启动不同类型的会话" tabindex="-1">启动不同类型的会话 <a class="header-anchor" href="#启动不同类型的会话" aria-label="Permalink to &quot;启动不同类型的会话&quot;">​</a></h2><p>HAPI 官方工作原理页给出了几种常用入口：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">hapi</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # 启动 Claude Code 会话</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">hapi</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> codex</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 启动 Codex 会话</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">hapi</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> gemini</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # 启动 Gemini CLI 会话</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">hapi</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> opencode</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # 启动 OpenCode 会话</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>你要控制哪个 CLI，就用哪条命令。</p><p>准备从手机端直接发起新会话时，可以额外启动后台 Runner：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">hapi</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> runner</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> start</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Runner 的作用是让网页或手机端在你不盯着终端的时候，也能拉起新的会话。</p><p>准备长期开着 HAPI 时，也可以顺手看一下 Runner 当前状态和日志目录：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">hapi</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> runner</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> status</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">ls</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> ~/.hapi/logs</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这一层看的是“远端能不能发起和接住会话”，不是“模型有没有选对”。<br> Runner 和日志都正常时，后面的排障就可以更放心地回到底层 CLI。</p><h2 id="第一次验证怎么做" tabindex="-1">第一次验证怎么做 <a class="header-anchor" href="#第一次验证怎么做" aria-label="Permalink to &quot;第一次验证怎么做&quot;">​</a></h2><p>第一次建议先从本机验证开始，不要一上来就把问题和公网混在一起：</p><ol><li>底层 CLI 本地单独跑一次，确认能正常走 小蓝中转站</li><li>执行 <code>hapi hub</code></li><li>在本机浏览器打开 <code>http://localhost:3006</code></li><li>再执行你对应的会话命令，比如 <code>hapi codex</code></li><li>在页面里发送一句短消息，例如“请告诉我当前会话是否在线”</li></ol><p>本机这一步通了以后，再切到：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">hapi</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> hub</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> --relay</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>然后再让手机或外部浏览器接进来。</p><p>只要这一步成功，说明三层都已经打通：</p><ul><li>CLI 本身能调用模型</li><li>HAPI Hub 能接住会话</li><li>远端页面能把消息送回本机</li></ul><p>如果这里失败，也尽量按层看，不要几层一起重装：</p><ul><li>本机 CLI 都不能回消息：先回对应 CLI 页面</li><li><code>http://localhost:3006</code> 都打不开：先看 HAPI Hub 有没有启动</li><li>页面能打开但没有会话：再看你是不是还没执行 <code>hapi</code>、<code>hapi codex</code> 这类会话命令</li><li>页面和会话都有，但手机端新建失败：再回到 Runner</li></ul><h2 id="使用建议" tabindex="-1">使用建议 <a class="header-anchor" href="#使用建议" aria-label="Permalink to &quot;使用建议&quot;">​</a></h2><h3 id="远程控制和模型网关分开看" tabindex="-1">远程控制和模型网关分开看 <a class="header-anchor" href="#远程控制和模型网关分开看" aria-label="Permalink to &quot;远程控制和模型网关分开看&quot;">​</a></h3><p>当你发现 HAPI 页面能打开，但模型回复失败时，不要第一反应去改 HAPI。</p><p>优先拆成两段看：</p><ol><li>底层 CLI 单独运行时，能不能直接走 小蓝中转站</li><li>HAPI 只负责把这个已经存在的会话同步出去</li></ol><p>这样排障速度会快很多。</p><h3 id="给远程场景单独建-key" tabindex="-1">给远程场景单独建 Key <a class="header-anchor" href="#给远程场景单独建-key" aria-label="Permalink to &quot;给远程场景单独建 Key&quot;">​</a></h3><p>计划在远端主机、长期运行的开发机或共享机器上用 HAPI 时，建议给底层 CLI 对应的远程环境单独建 Key，例如：</p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span>Remote-Claude</span></span>
<span class="line"><span>Remote-Codex</span></span>
<span class="line"><span>Remote-OpenCode</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>这样一旦需要停用远端环境，只需要处理那一把 Key，不会影响你本地桌面或其他设备。</p><h3 id="会话稳定后再考虑公网" tabindex="-1">会话稳定后再考虑公网 <a class="header-anchor" href="#会话稳定后再考虑公网" aria-label="Permalink to &quot;会话稳定后再考虑公网&quot;">​</a></h3><p>HAPI 很适合远程操作，但这也意味着你的开发会话可能被放到公网入口后面。正式长期使用前，先确认：</p><ul><li>访问令牌保存妥当</li><li>不把 <code>~/.hapi/settings.json</code> 随手同步出去</li><li>共享设备上的浏览器会话及时退出</li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="页面能打开-但发送消息后没有模型回复" tabindex="-1">页面能打开，但发送消息后没有模型回复 <a class="header-anchor" href="#页面能打开-但发送消息后没有模型回复" aria-label="Permalink to &quot;页面能打开，但发送消息后没有模型回复&quot;">​</a></h3><p>这通常不是 HAPI Hub 地址写错，而是底层 CLI 没有先跑通。</p><p>例如你正在用 <code>hapi codex</code>，那就先退出 HAPI，单独回到终端执行 Codex 的最小测试。只有 Codex 本地能正常走 小蓝中转站，HAPI 才有东西可同步。</p><h3 id="hapi-能跑-手机端看不到会话" tabindex="-1"><code>hapi</code> 能跑，手机端看不到会话 <a class="header-anchor" href="#hapi-能跑-手机端看不到会话" aria-label="Permalink to &quot;\`hapi\` 能跑，手机端看不到会话&quot;">​</a></h3><p>优先检查：</p><ul><li>Hub 是否已经先启动</li><li>你当前是 <code>hapi hub</code> 还是 <code>hapi hub --relay</code></li><li>会话启动命令是否和你要控制的 CLI 对应</li></ul><p>如果只是本地模式启动 <code>hapi hub</code>，外部网络设备一般不会直接拿到可访问入口。</p><p>准备把 CLI 跑在另一台机器上，而 Hub 不在本机时，还要继续确认这台 CLI 机器有没有正确登录 Hub。<br> HAPI 官方提供的常用检查命令是：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">hapi</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> status</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">hapi</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> login</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这一层没连上时，看起来也会像“手机看不到会话”，但问题其实不是 Relay，而是 CLI 根本没连到目标 Hub。</p><p>是在同一 Wi-Fi 下测试时，别忘了再检查两件事：</p><ul><li><code>HAPI_LISTEN_HOST</code> 是否仍然是默认的 <code>127.0.0.1</code></li><li>系统防火墙有没有拦住 3006 端口</li></ul><p>这两层没放开时，Hub 在本机可以访问，手机同网段却还是会像“完全找不到页面”。</p><h3 id="hapi-装不上-或者装完命令异常" tabindex="-1">HAPI 装不上，或者装完命令异常 <a class="header-anchor" href="#hapi-装不上-或者装完命令异常" aria-label="Permalink to &quot;HAPI 装不上，或者装完命令异常&quot;">​</a></h3><p>先看是不是 npm 镜像导致的平台包没有同步齐。HAPI 官方对这一点有明确提醒。</p><p>最简单的处理方式通常是：</p><ol><li>临时切回 <code>https://registry.npmjs.org</code></li><li>重新安装 HAPI</li><li>装完后再把 registry 切回镜像</li></ol><h3 id="想用手机直接创建新会话" tabindex="-1">想用手机直接创建新会话 <a class="header-anchor" href="#想用手机直接创建新会话" aria-label="Permalink to &quot;想用手机直接创建新会话&quot;">​</a></h3><p>这不是普通 <code>hapi hub</code> 的职责，通常还需要：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">hapi</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> runner</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> start</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Runner 没启动时，手机端更适合“接管已有会话”，而不是“凭空创建一条新会话”。</p><h3 id="windows-上为什么只能部分使用-hapi" tabindex="-1">Windows 上为什么只能部分使用 HAPI <a class="header-anchor" href="#windows-上为什么只能部分使用-hapi" aria-label="Permalink to &quot;Windows 上为什么只能部分使用 HAPI&quot;">​</a></h3><p>HAPI 官方 FAQ 当前明确说明，远程终端能力主要面向 macOS 和 Linux。<br> 在 Windows 上使用时，最适合把它理解成“远程接管已经存在的 AI 会话”，而不是完整替代一台 Unix 开发机。</p><p>也就是说，Windows 上看到某些远程终端相关能力不完整，并不一定是你配置错了，很多时候是平台支持范围本来就不同。</p><h2 id="进阶" tabindex="-1">进阶 <a class="header-anchor" href="#进阶" aria-label="Permalink to &quot;进阶&quot;">​</a></h2><p>已经能稳定远程接入，但还想继续优化入口、网络路径或远端主机部署时，再看 <a href="/apps/hapi-advanced">Hapi 进阶：优选 IP 配置</a>。</p>`,110)])])}const b=a(p,[["render",t]]);export{u as __pageData,b as default};
